import"./app-yIULqX0W.js";window.Auth&&window.Auth.isLoggedIn()&&(window.location.href="/pages/dashboard.html");const a=document.getElementById("login-form");a&&a.addEventListener("submit",async o=>{o.preventDefault();const e=document.getElementById("submit-btn"),t=document.getElementById("login-error");t.classList.remove("visible"),e.disabled=!0,e.innerHTML='<span class="spinner"></span> Signing in…';try{const n=document.getElementById("email").value,i=document.getElementById("password").value,s=new URLSearchParams;s.append("username",n),s.append("password",i);const d=await window.apiFetch("/auth/login",{method:"POST",headers:{"Content-Type":"application/x-www-form-urlencoded"},body:s});window.Auth.set(d.access_token,{email:n}),window.toast("Login successful","success"),setTimeout(()=>window.location.href="/pages/dashboard.html",700)}catch(n){window.toast(n.message,"error"),t.textContent=n.message,t.classList.add("visible")}finally{e&&(e.disabled=!1,e.innerHTML="Sign in")}});
